   362	func doRenderShortcode(
   363		ctx context.Context,
   364		level int,
   365		ts *tplimpl.TemplateStore,
   366		sc *shortcode,
   367		parent *ShortcodeWithPage,
   368		po *pageOutput,
   369		isRenderString bool,
   370	) (shortcodeRenderer, error) {
   371		var tmpl *tplimpl.TemplInfo
   372		p := po.p
   373	
   374		// Tracks whether this shortcode or any of its children has template variations
   375		// in other languages or output formats. We are currently only interested in
   376		// the output formats.
   377		var hasVariants bool
   378	
   379		if sc.isInline {
   380			if !p.s.ExecHelper.Sec().EnableInlineShortcodes {
   381				return zeroShortcode, nil
   382			}
   383			templatePath := path.Join("_inline_shortcode", p.Path(), sc.name)
   384			if sc.isClosing {
   385				templStr := sc.innerString()
   386	
   387				var err error
   388				tmpl, err = ts.TextParse(templatePath, templStr)
   389				if err != nil {
   390					if isRenderString {
   391						return zeroShortcode, p.wrapError(err)
   392					}
   393					fe := herrors.NewFileErrorFromName(err, p.File().Filename())
   394					pos := fe.Position()
   395					pos.LineNumber += p.posOffset(sc.pos).LineNumber
   396					fe = fe.UpdatePosition(pos)
   397					return zeroShortcode, p.wrapError(fe)
   398				}
   399	
   400			} else {
   401				// Re-use of shortcode defined earlier in the same page.
   402				tmpl = ts.TextLookup(templatePath)
   403				if tmpl == nil {
   404					return zeroShortcode, fmt.Errorf("no earlier definition of shortcode %q found", sc.name)
   405				}
   406			}
   407		} else {
   408			ofCount := map[string]int{}
   409			include := func(match *tplimpl.TemplInfo) bool {
   410				ofCount[match.D.OutputFormat]++
