   412			}
   413			base, layoutDescriptor := po.GetInternalTemplateBasePathAndDescriptor()
   414	
   415			// With shortcodes/mymarkdown.md (only), this allows {{% mymarkdown %}} when rendering HTML,
   416			// but will not resolve any template when doing {{< mymarkdown >}}.
   417			layoutDescriptor.AlwaysAllowPlainText = sc.doMarkup
   418			q := tplimpl.TemplateQuery{
   419				Path:     base,
   420				Name:     sc.name,
   421				Category: tplimpl.CategoryShortcode,
   422				Desc:     layoutDescriptor,
   423				Sites:    p.s.siteVector,
   424				Consider: include,
   425			}
